#include <string.h>

static inline int em_check_modbus_write(const char *payload, double payload_len) {
    if (payload == NULL) return 0;
    int len = (int)payload_len;

    // Minimum MBAP header (7 bytes) + function code (1 byte) = 8 bytes
    if (len < 8) return 0;

    const unsigned char *data = (const unsigned char *)payload;

    // Check Modbus/TCP protocol ID at bytes 2-3 (must be 0x0000)
    if (data[2] != 0x00 || data[3] != 0x00) return 0;

    // Function code is at byte 7 (after 7-byte MBAP header)
    unsigned char func_code = data[7];

    // Detect write function codes:
    //  5 = Write Single Coil
    //  6 = Write Single Register
    // 15 = Write Multiple Coils
    // 16 = Write Multiple Registers
    // 22 = Mask Write Register
    // 23 = Read/Write Multiple Registers
    if (func_code == 5 || func_code == 6 ||
        func_code == 15 || func_code == 16 ||
        func_code == 22 || func_code == 23) {
        return 1;
    }

    return 0;
}
